INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Posso dar banho se o coto umbilical ainda não caiu?', 'Sim! Só toma cuidado para não molhar muito. Depois seca bem.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como limpar o nariz entupido do bebê?', 'Soro fisiológico com conta-gotas. Coloca algumas gotas, depois limpa com gaze. Simples!', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Bebê pode usar sabonete?', 'Sim! Mas sabonete neutro ou específico para bebê. Evita rosto.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como cortar a unha do bebê sem machucar?', 'Tesoura de bebê ou cortador. Faz quando ele está dormindo. Cuidado!', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Meu bebê tem sapinho na boca, como limpar?', 'Gaze molhada em água morna. Limpa a língua e boca delicadamente. Se não passar, procura o pediatra.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Bebê pode usar talco?', 'Melhor não! Talco pode prejudicar os pulmões. Usa hidratante em vez disso.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como tratar assadura?', 'Deixa o bebê sem fralda quando possível. Pomada de zinco ajuda. Se não melhorar, procura o pediatra.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Posso usar lenço umedecido desde o primeiro dia?', 'Sim! Lenço neutro é ótimo. Ou água morna com gaze.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como lavar a roupa do bebê?', 'Lava com sabão neutro. Pode ser junto com a roupa da família! Não precisa de sabão especial.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Bebê pode usar amaciante?', 'Melhor não! Pode irritar a pele. Roupa de bebê é macia mesmo sem amaciante.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como limpar as orelhas do bebê?', 'Gaze molhada em água morna. Limpa a parte externa. Nunca coloca nada dentro!', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Meu bebê está amarelinho, é icterícia?', 'Pode ser! Icterícia é comum em recém-nascidos. Procura o pediatra para confirmar.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Icterícia é perigosa?', 'Leve, não! Mas icterícia muito alta pode prejudicar. Por isso o pediatra acompanha.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Como tratar icterícia?', 'Geralmente com fototerapia (luz especial). Seu bebê fica embaixo da luz por algumas horas.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Preciso dar sol para icterícia?', 'Não! Fototerapia é mais eficaz. Mas sol natural também ajuda um pouco.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Icterícia passa sozinha?', 'Geralmente sim! Mas precisa acompanhar com o pediatra.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Meu bebê está muito amarelo, é grave?', 'Pode ser! Procura o pediatra urgentemente para medir o nível de bilirrubina.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Quanto tempo dura a fototerapia?', 'Depende do nível de bilirrubina! Pode ser horas ou dias.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Posso amamentar durante a fototerapia?', 'Sim! Continua amamentando normalmente.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Icterícia volta depois de passar?', 'Raramente! Mas se voltar, procura o pediatra.', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('ictericia', 'Meu bebê tem icterícia e está molinho, é perigoso?', 'Sim! Icterícia muito alta pode afetar o sistema nervoso. Procura emergência!', 'ictericia', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Meu bebê golfa muito, é refluxo?', 'Pode ser! Golfada é comum. Mas se golfa muito ou o bebê fica irritado, pode ser refluxo.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Como diferenciar golfada de vômito?', 'Golfada é pouca quantidade que sai pela boca. Vômito é mais quantidade e com força.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Como aliviar refluxo?', 'Coloca o bebê mais verticalizado depois de mamar. Espera 30 minutos antes de deitar.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Refluxo é perigoso?', 'Leve, não! Mas refluxo severo pode prejudicar. Procura o pediatra se o bebê não ganha peso.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Meu bebê vomita jato de leite, é refluxo?', 'Pode ser! Vômito em jato é mais preocupante. Procura o pediatra.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Posso dar remédio para refluxo?', 'Sim! Mas só com receita do pediatra. Alguns remédios ajudam muito.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Refluxo passa com o tempo?', 'Sim! Geralmente melhora depois de 6-12 meses quando o bebê começa a sentar.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Meu bebê chora depois de mamar, pode ser refluxo?', 'Pode ser! Refluxo causa desconforto. Tenta as posições que mencionei.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Bebê com refluxo pode dormir?', 'Sim! Mas coloca mais verticalizado. Usa um travesseiro de espuma (depois de 1 ano).', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('refluxo', 'Refluxo prejudica o ganho de peso?', 'Pode! Se o bebê não está ganhando peso, procura o pediatra para investigar.', 'refluxo', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Meu bebê nasceu prematuro, o que muda?', 'Você calcula a idade corrigida! Se nasceu 2 meses antes, subtrai 2 meses da idade real.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Prematuro pode pegar frio fácil?', 'Sim! Sistema imunológico ainda está se desenvolvendo. Cuidado com aglomerações.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Quando prematuro começa a sorrir?', 'Conforme a idade corrigida! Se nasceu 2 meses antes, sorri 2 meses depois.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Meu prematuro está com febre, devo ir para o hospital?', 'Sim! Prematuro com febre é mais preocupante. Procura emergência.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Prematuro pode ser vacinado normalmente?', 'Sim! Mas conforme a idade corrigida.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Meu prematuro está atrasado no desenvolvimento, é normal?', 'Sim! Compara conforme a idade corrigida, não a idade real.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Quando prematuro pode sair de casa?', 'Depois de algumas semanas, quando está mais estável. Converse com o pediatra!', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('prematuridade', 'Prematuro precisa de cuidados especiais?', 'Sim! Mais higiene, cuidado com temperatura, acompanhamento frequente com pediatra.', 'prematuridade', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Meu bebê tem língua presa, é problema?', 'Pode ser! Se atrapalha a amamentação, precisa avaliar com o pediatra.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Como saber se o freio está muito curto?', 'Se o bebê tem dificuldade para mamar, faz barulho estranho, ou você sente dor.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Freio lingual precisa de cirurgia?', 'Nem sempre! Alguns pediatras recomendam, outros não. Depende do caso.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'A cirurgia de freio dói?', 'Não! É rápida e sem dor. Bebê nem sente!', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Quando devo fazer a cirurgia de freio?', 'Se atrapalha a amamentação, quanto antes melhor! Geralmente nos primeiros meses.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Depois da cirurgia, o bebê consegue mamar melhor?', 'Sim! Geralmente melhora muito!', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Freio lingual atrapalha a fala depois?', 'Se tratar cedo, não! Mas se deixar, pode atrapalhar.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Meu bebê faz click ao mamar, pode ser freio?', 'Sim! Click é sinal de que algo está errado na pega. Procura o pediatra.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Bebê com freio pode ganhar peso?', 'Pode, mas geralmente ganha menos. Por isso é importante tratar.', 'freio_lingual', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('freio_lingual', 'Qual é o melhor momento para fazer a cirurgia?', 'Quanto antes, melhor! Primeiros meses são ideais.', 'freio_lingual', 'pt', 0, 'true');